```html name="card-origem-css-extract.html" url="https://github.com/Kodux78k/oiDual--Y-/blob/c4820f8f600434240f53f9da489255f72ea75899/M0D/VWRDI/index.html#L19-L101"
<!-- ========== CSS DO CARD ORIGEM (Para adicionar no symbol.html) ========== -->

<style>
    /* --- AETHER: FÍSICA CINEMATOGRÁFICA --- */
    body { overflow: auto; padding: 0; }

    .card-origem {
        transition: all 0.5s cubic-bezier(0.32, 0.72, 0, 1);
        overflow: hidden;
        will-change: transform, padding, height;
        background: rgba(10, 12, 25, 0.4);
        backdrop-filter: blur(15px);
        border-radius: 28px;
        margin: 2px;
        border: 1px solid rgba(255, 255, 255, 0.08);
        position: relative;
    }

    .hero-top { cursor: pointer; }

    /* Elementos que colapsam */
    .hero-slider, .input-row, .btn-row, .time-sub {
        transition: all 0.4s cubic-bezier(0.32, 0.72, 0, 1);
        transform-origin: top;
        opacity: 1;
        max-height: 500px;
    }

    /* Estado Colapsado */
    .card-origem.is-collapsed {
        padding-bottom: 12px;
        background: rgba(10, 12, 25, 0.6);
    }

    .card-origem.is-collapsed .hero-slider,
    .card-origem.is-collapsed .input-row,
    .card-origem.is-collapsed .btn-row,
    .card-origem.is-collapsed .time-sub {
        opacity: 0;
        max-height: 0;
        margin: 0;
        padding: 0;
        pointer-events: none;
        transform: translateY(-10px) scale(0.98);
    }

    /* Atmosfera Visual */
    .orb-bg {
        position: fixed;
        width: 70vw;
        height: 70vw;
        border-radius: 50%;
        filter: blur(80px);
        z-index: -1;
        opacity: 0.25;
        pointer-events: none;
    }

    #orb-top { 
        top: -25%; 
        right: -15%; 
        background: radial-gradient(circle, #4facfe 0%, #00f2fe 100%); 
    }

    #orb-bottom { 
        bottom: -25%; 
        left: -15%; 
        background: radial-gradient(circle, #667eea 0%, #764ba2 100%); 
    }

    #particles-js {
        position: fixed;
        top: 0; left: 0; width: 100%; height: 100%;
        z-index: -1;
    }

    .frase {
        text-align: center;
        font-size: 0.75rem;
        opacity: 0.4;
        margin: 12px 0;
        letter-spacing: 2px;
        text-transform: uppercase;
        font-weight: 600;
    }

    /* Ajustes de Layout */
    .app-header {
        padding: 16px 20px;
        display: flex;
        justify-content: space-between;
        align-items: center;
    }
</style>
```

