## 🔧 **JavaScript para integrar (Colapso do Card):**

```javascript
<script>
    document.addEventListener('DOMContentLoaded', () => {
        const card = document.getElementById('cardOrigem');
        const heroArea = document.getElementById('heroTouchArea');
        const greeting = document.getElementById('heroGreeting');
        const subtitle = document.getElementById('heroSubtitle');
        const toggleOrigemBtn = document.getElementById('toggleOrigemBtn');

        // 1. Identidade & Sincronização
        const userName = localStorage.getItem('di_userName') || 'Dual';
        const infodoseName = localStorage.getItem('di_infodoseName') || 'Infodose';

        const runChronos = () => {
            const hour = new Date().getHours();
            let msg = "Bom dia";
            if (hour >= 12 && hour < 18) msg = "Boa tarde";
            if (hour >= 18 || hour < 5) msg = "Boa noite";

            if (greeting) greeting.textContent = `${msg}, ${userName}`;
            if (subtitle) subtitle.textContent = `Dual.Infodose ${infodoseName} online.`;
        };
        runChronos();

        // 2. Lógica de Colapso (Persistence)
        const KEY_COLLAPSE = 'di_card_collapsed';

        const toggleCollapse = (forceState = null) => {
            const isNow = forceState !== null ? forceState : !card.classList.contains('is-collapsed');
            if (isNow) card.classList.add('is-collapsed');
            else card.classList.remove('is-collapsed');

            localStorage.setItem(KEY_COLLAPSE, isNow ? '1' : '0');
            if (navigator.vibrate) navigator.vibrate(8);
        };

        // Estado inicial baseado em histórico ou hora
        const savedState = localStorage.getItem(KEY_COLLAPSE);
        if (savedState === '1') toggleCollapse(true);
        else if (savedState === null) {
            const h = new Date().getHours();
            if (h >= 21 || h < 6) toggleCollapse(true);
        }

        // Eventos de Clique
        heroArea?.addEventListener('click', () => toggleCollapse());
        toggleOrigemBtn?.addEventListener('click', () => toggleCollapse());

        // 3. Controle do Console
        const consoleToggle = document.getElementById('consoleToggle');
        const consolePanel = document.getElementById('consolePanel');
        const consoleClose = document.getElementById('consoleClose');

        consoleToggle?.addEventListener('click', () => {
            consolePanel.setAttribute('aria-hidden', 'false');
            consolePanel.classList.add('active');
        });

        consoleClose?.addEventListener('click', () => {
            consolePanel.setAttribute('aria-hidden', 'true');
            consolePanel.classList.remove('active');
        });
    });
</script>
```

