      --cu-6: #C9A84C;
      --cu-7: #FFD700;
      --kob-voice-primary: #C9A84C;
      --kob-voice-secondary: #8B4513;
      --kob-voice-accent: #F0C060;
      --arch-color: #C9A84C;
      --arch-glow: rgba(201,168,76,0.35);
      --arch-glow-strong: rgba(201,168,76,0.6);
