    body.light { --bg: linear-gradient(to bottom,#666,#e0e0e0); --text: #444; }
    body.medium { --bg: linear-gradient(to bottom,#555,#333); --text: #eee; }
    body.vibe { --bg: linear-gradient(135deg,#00d8d8,#d800d8); --text: #fff; }

    * { box-sizing: border-box; margin: 0; padding: 0; }
    html, body { font-family: var(--font-family, sans-serif); width: 100%; height: 100%; overflow: hidden; }
    body { 
      font-family: 'Montserrat',sans-serif; 
      display: flex; 
      flex-direction: column; 
      align-items: center; 
      padding: 20px; 
      background: var(--bg); 
      color: var(--text); 
      transition: background var(--slow), color var(--slow); 
      animation: fadeIn var(--slow) ease forwards; 
    }

    @keyframes fadeIn { from { opacity:0; transform:translateY(20px); } to { opacity:1; transform:translateY(0); } }
    @keyframes clickPulse { 0%,100%{opacity:1} 50%{opacity:0.7} }
    @keyframes pulse { 0%,100%{transform:scale(1)} 50%{transform:scale(1.012)} }
    @keyframes orbSpin { to { transform:rotate(360deg); } }
    @keyframes orbPulse { from { transform:scale(1); } to { transform:scale(1.18); } }

    /* ========== CARD ORIGEM (VWRDI) ========== */
    .card-origem {
      transition: all 0.5s cubic-bezier(0.32, 0.72, 0, 1);
      overflow: hidden;
      will-change: transform, padding, height;
      background: rgba(10, 12, 25, 0.4);
      backdrop-filter: blur(15px);
      border-radius: 28px;
      margin: 2px;
      border: 1px solid rgba(255, 255, 255, 0.08);
      position: relative;
      width: 90%;
      max-width: 500px;
      padding: 20px;
    }

    .hero-top { cursor: pointer; }

    .hero-slider, .input-row, .btn-row, .time-sub {
      transition: all 0.4s cubic-bezier(0.32, 0.72, 0, 1);
      transform-origin: top;
      opacity: 1;
      max-height: 500px;
    }

    .card-origem.is-collapsed {
      padding-bottom: 12px;
      background: rgba(10, 12, 25, 0.6);
    }

    .card-origem.is-collapsed .hero-slider,
    .card-origem.is-collapsed .input-row,
    .card-origem.is-collapsed .btn-row,
    .card-origem.is-collapsed .time-sub {
      opacity: 0;
      max-height: 0;
