      opacity: 0.7;
    }

    .hero-meta-row {
      display: flex;
      gap: 12px;
      margin-top: 12px;
      font-size: 0.8rem;
    }

    .time-chip {
      background: rgba(255,255,255,0.08);
      padding: 4px 8px;
