      font-size: 0.9rem;
    }

    .btn-row {
      display: flex;
      gap: 8px;
      margin-top: 12px;
    }

    .btn {
      flex: 1;
      padding: 8px 12px;
      background: linear-gradient(135deg, rgba(201,168,76,0.15), rgba(139,69,19,0.15));
