    /* ========== SYMBOL BAR v2 ========== */
    .symbol-bar {
      position: fixed;
      left: 16px;
      top: 50%;
      transform: translateY(-50%);
      z-index: var(--z-hud);
      display: flex;
      flex-direction: column;
      align-items: center;
      padding: 10px 8px;
      gap: 0;
      background: rgba(6,6,21,0.88);
      backdrop-filter: blur(20px) saturate(200%);
      border: 1px solid var(--border);
      box-shadow: 0 0 0 1px rgba(0,0,0,0.5), 0 8px 40px rgba(0,0,0,0.7), inset 0 1px 0 rgba(255,255,255,0.06), 0 0 30px var(--arch-glow);
      border-radius: 28px;
      user-select: none;
      touch-action: none;
      transition: opacity 0.6s ease, top 0.35s cubic-bezier(0.175,0.885,0.32,1.275), left 0.35s cubic-bezier(0.175,0.885,0.32,1.275), border-radius 0.25s ease, border-color 0.5s ease, box-shadow 0.6s ease;
    }

    .symbol-bar::before {
      content: '';
      position: absolute;
      top: 0;
      left: 16%;
      right: 16%;
      height: 2px;
      border-radius: 0 0 4px 4px;
      background: linear-gradient(90deg, transparent, var(--kob-voice-primary), transparent);
      opacity: 0.7;
      transition: background 0.5s ease;
    }

    .symbol-bar.idle { opacity: 0.18; }
    .symbol-bar.idle:hover { opacity: 1; }
    .symbol-bar.is-dragging { opacity: 0.92; transition: none; will-change: top,left; }

