      justify-content: center;
      flex-shrink: 0;
      transform-origin: center center;
      transform: scale(var(--kblx-item-scale,1));
      opacity: var(--kblx-item-opacity,1);
      z-index: var(--kblx-item-z,1);
      transition: transform 0.28s ease, opacity 0.28s ease;
      position: relative;
    }

