      align-items: center;
      justify-content: center;
      background: rgba(255,255,255,0.04);
      color: var(--mist);
      font-size: 16px;
      cursor: pointer;
      flex-shrink: 0;
      position: relative;
      outline: none;
      font-family: var(--body);
      transition: all 0.2s ease;
      box-shadow: inset 0 1px 0 rgba(255,255,255,0.07), 0 2px 4px rgba(0,0,0,0.4);
    }

    .symbol-button:hover {
      background: rgba(255,255,255,0.1);
      border-color: var(--kob-voice-primary);
      color: var(--kob-voice-primary);
      box-shadow: 0 0 14px var(--arch-glow), inset 0 1px 0 rgba(255,255,255,0.1);
    }

    .symbol-button:active {
      transform: scale(0.86);
    }

    .symbol-button.main-toggle {
      background: linear-gradient(160deg, rgba(26,20,10,0.95), rgba(5,5,10,0.98));
      color: var(--kob-voice-primary);
      border-color: var(--kob-voice-primary);
      font-size: 22px;
      font-weight: bold;
      box-shadow: 0 0 16px var(--arch-glow), inset 0 1px 0 rgba(255,255,255,0.1), inset 0 -1px 0 rgba(0,0,0,0.4);
    }

    .toggle-wrap {
      display: flex;
      align-items: center;
      justify-content: center;
      margin-bottom: 4px;
    }

    .tts-orb-mini {
      width: 32px;
      height: 32px;
      display: flex;
      align-items: center;
      justify-content: center;
    }

    .orb {
      width: 100%;
      height: 100%;
      border-radius: 50%;
      display: grid;
      place-items: center;
    }

    .orb-core {
      width: 80%;
      height: 80%;
      border-radius: 50%;
      background: radial-gradient(circle at 28% 28%, var(--kob-voice-accent) 0%, rgba(255,255,255,0.08) 12%, transparent 55%), radial-gradient(circle at 72% 72%, var(--kob-voice-primary) 0%, var(--kob-voice-secondary) 100%);
      box-shadow: 0 0 18px var(--kob-voice-primary), 0 0 8px rgba(255,255,255,0.1) inset;
      animation: orbSpin var(--orb-speed) linear infinite;
      transition: background 0.5s ease, box-shadow 0.5s ease;
    }

    .speaking .orb-core {
      animation: orbSpin 1.8s linear infinite, orbPulse 0.45s ease-in-out infinite alternate;
      box-shadow: 0 0 30px var(--kob-voice-primary), 0 0 12px rgba(255,255,255,0.15) inset;
    }

    .hud-info {
      font-size: 8px;
      font-family: var(--mono);
      color: var(--kob-voice-primary);
      text-transform: uppercase;
      letter-spacing: 1.5px;
      font-weight: 700;
      padding: 5px 6px;
      margin-top: 4px;
      border-top: 1px solid var(--border);
      pointer-events: none;
      opacity: 0.75;
      white-space: nowrap;
      transition: color 0.5s ease, border-color 0.5s ease;
    }

    /* ========== ARCH OVERLAY ========== */
    #arch-overlay {
      position: fixed;
      inset: 0;
      z-index: var(--z-overlay);
      display: none;
      align-items: center;
      justify-content: center;
      background: rgba(2,2,10,0.75);
      backdrop-filter: blur(8px);
    }

    #arch-overlay.open {
      display: flex;
    }

    .arch-wheel {
      display: flex;
      flex-wrap: wrap;
      gap: 8px;
      justify-content: center;
      max-width: 380px;
      background: linear-gradient(135deg, rgba(10,10,30,0.97), rgba(5,5,18,0.99));
      border: 1px solid var(--border);
      border-radius: 22px;
      padding: 18px;
      box-shadow: 0 0 60px var(--arch-glow), 0 30px 60px rgba(0,0,0,0.8);
      animation: fadeIn .28s cubic-bezier(.34,1.56,.64,1) both;
    }

    .arch-chip {
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 4px;
      padding: 8px 10px;
      border-radius: 12px;
      border: 1px solid transparent;
      cursor: pointer;
      transition: all 0.18s;
      font-family: var(--mono);
      min-width: 56px;
    }

    .arch-chip:hover {
      transform: scale(1.1);
      border-color: currentColor;
      background: rgba(255,255,255,0.04);
    }

    .a-orb {
      width: 26px;
      height: 26px;
      border-radius: 50%;
      background: radial-gradient(circle at 35% 30%, var(--a-color), transparent 50%), radial-gradient(circle at 70% 70%, var(--a-prim), var(--a-sec));
      box-shadow: 0 0 10px currentColor;
    }

    .a-name {
      font-size: 7px;
      letter-spacing: 1.5px;
      text-transform: uppercase;
      color: rgba(255,255,255,0.55);
    }

    .a-freq {
      font-size: 6px;
      color: rgba(255,255,255,0.3);
      letter-spacing: 1px;
    }

    /* ========== MISC ========== */
    #themeToggle {
      position: absolute;
      top: 60px;
      left: 50%;
      transform: translateX(-50%);
      width: 30px;
      height: 30px;
      border: 1px solid var(--text);
      border-radius: 50%;
      background: transparent;
      opacity: .3;
      cursor: pointer;
      transition: opacity var(--med), border-color var(--med);
      z-index: 10;
    }

    #themeToggle:hover { opacity: 0.8; }

    #themeToggle::before {
      content: '';
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%,-50%);
      width: 12px;
      height: 12px;
      border-radius: 50%;
      background: var(--text);
      opacity: 0.2;
    }

    #particles-js {
      position: fixed;
      inset: 0;
      z-index: 0;
    }

    .response-container {
      position: fixed;
      left: 20px;
      right: 20px;
      bottom: 160px;
      padding: 12px;
      background: rgba(0,0,0,0.3);
      backdrop-filter: blur(8px);
      border-radius: 20px;
      max-height: calc(100vh - 200px);
      overflow-y: auto;
      z-index: 1;
      transition: background var(--slow);
      animation: fadeIn var(--slow) ease forwards;
    }

    .page {
      display: none;
      opacity: 0;
      transition: opacity var(--slow);
    }

    .page.active {
      display: block;
      opacity: 1;
    }

    .response-block {
      margin: 1rem 0;
      padding: 1.3rem;
      border-radius: 12px;
      line-height: 1.8;
      position: relative;
      overflow: hidden;
      animation: fadeIn var(--slow) ease forwards;
      transition: box-shadow var(--fast), transform var(--fast);
      background: linear-gradient(135deg, rgba(0,255,255,.2), rgba(0,100,100,.1));
      border-left: 4px solid #0ff;
    }

    .response-block:hover {
      box-shadow: 0 0 15px rgba(0,255,255,.4);
    }
  </style>
</head>
<body>

  <!-- Particles JS -->
  <div id="particles-js"></div>

  <!-- Theme Toggle -->
  <button aria-label="Alternar tema" id="themeToggle" title="Alternar tema"></button>

  <!-- ========== CARD ORIGEM (VWRDI INTEGRADO) ========== -->
  <section class="card-origem" id="cardOrigem">
    <div class="hero-card hero-embedded" id="heroTouchArea">
      <div class="hero-top">
        <div class="hero-main">
          <div class="hero-greeting" id="heroGreeting">Bom dia, Dual</div>
          <div class="hero-subtitle" id="heroSubtitle">Sincronizando tua dose...</div>
        </div>
      </div>

      <div class="hero-meta-row">
        <span class="time-chip" id="timeNow">--:--</span>
        <span id="moodLabel" class="label-mood">Estado Mental</span>
      </div>
    </div>

    <div id="timeSub" class="time-sub"></div>

    <div class="input-row">
      <label for="intentInput">Intenção / vibração</label>
      <input id="intentInput" placeholder="O que pretendes ativar?" />
    </div>

    <div class="btn-row">
      <button class="btn" id="btnDocs">
        <span class="emoji">📂</span>
        <span>Docs & Apps</span>
      </button>
      <button class="btn" id="btnAddApp">
        <span class="emoji">＋</span>
        <span>Novo app</span>
      </button>
    </div>
  </section>

  <!-- ========== KEY MANAGER PANEL ========== -->
  <div class="keymgr-panel" id="keymgrPanel">
    <div class="keymgr-hd">
      <h3>Chaves & Treinamentos — Dual.Infodose</h3>
      <button class="keymgr-close" id="keymgrClose">✕</button>
    </div>
    <p class="user-info">Usuário: <span id="keymgrUserName"></span> — Assistente: <span id="keymgrAssistantName"></span></p>
    <div class="keymgr-grid">
      <div class="cardx">
        <h4>OpenRouter — Chaves</h4>
        <div class="row">
          <input id="orKeyName" placeholder="Nome da chave (ex.: Pessoal, Work)" type="text">
          <input id="orKeyValue" placeholder="Cole sua chave sk-..." type="password">
          <button class="btnx" id="btnPasteKey">Colar</button>
          <button class="btnx" id="btnSaveKey">Salvar</button>
        </div>
        <div class="list" id="keysList"></div>
      </div>
      <div class="cardx">
        <h4>Treinamento Base (TXT)</h4>
        <div class="row">
          <input id="baseTrainName" placeholder="Nome (ex.: Unificado v6)" type="text">
          <button class="btnx" id="btnLoadBaseTxt">Carregar TXT</button>
          <input accept=".txt" id="baseTrainFile" style="display:none" type="file">
          <button class="btnx" id="btnApplyBaseTxt">Aplicar</button>
          <label class="switch"><input checked id="baseTrainEnabled" type="checkbox"> Ativo</label>
        </div>
        <textarea id="baseTrainText" placeholder="Conteúdo do TXT base"></textarea>
      </div>
      <div class="cardx">
        <h4>Treinamentos Extras / Ativações</h4>
        <div class="row">
          <input id="extraName" placeholder="Nome do extra/ativação" type="text">
          <button class="btnx" id="btnLoadExtraTxt">Adicionar TXT</button>
          <input accept=".txt" id="extraFile" style="display:none" type="file">
        </div>
        <div class="list" id="extrasList"></div>
      </div>
    </div>
  </div>

  <!-- ========== SYMBOL BAR v2 ========== -->
  <div class="symbol-bar floating" id="symbolBar">
    <div class="toggle-wrap">
      <button class="symbol-button main-toggle" id="sbToggleBtn" title="Menu">≡</button>
    </div>
    <button class="symbol-button" id="btn-arch" title="Arquétipo (1.5s = chaves, 3s = wheel)">
      <div class="tts-orb-mini"><div class="orb" id="main-orb"><div class="orb-core"></div></div></div>
    </button>
    <div class="hud-info" id="hudStatus">KOBLLUX</div>
  </div>

  <!-- ========== ARCH OVERLAY ========== -->
  <div id="arch-overlay">
    <div class="arch-wheel" id="archWheel"></div>
  </div>

  <script>
    // ========== INITIALIZATION ========== 
    document.addEventListener('DOMContentLoaded', () => {
      // Setup Card Origem
      const card = document.getElementById('cardOrigem');
      const heroArea = document.getElementById('heroTouchArea');
      const greeting = document.getElementById('heroGreeting');
      const subtitle = document.getElementById('heroSubtitle');

      const userName = localStorage.getItem('di_userName') || 'Dual';
      const infodoseName = localStorage.getItem('di_infodoseName') || 'Infodose';

      const runChronos = () => {
        const hour = new Date().getHours();
        let msg = "Bom dia";
        if (hour >= 12 && hour < 18) msg = "Boa tarde";
        if (hour >= 18 || hour < 5) msg = "Boa noite";

        if (greeting) greeting.textContent = `${msg}, ${userName}`;
        if (subtitle) subtitle.textContent = `Dual.Infodose ${infodoseName} online.`;
      };
      runChronos();

      // Colapso do Card
      const KEY_COLLAPSE = 'di_card_collapsed';
      const toggleCollapse = (forceState = null) => {
        const isNow = forceState !== null ? forceState : !card.classList.contains('is-collapsed');
        card.classList.toggle('is-collapsed', isNow);
        localStorage.setItem(KEY_COLLAPSE, isNow ? '1' : '0');
        if (navigator.vibrate) navigator.vibrate(8);
      };

      const savedState = localStorage.getItem(KEY_COLLAPSE);
      if (savedState === '1') toggleCollapse(true);
      else if (savedState === null) {
        const h = new Date().getHours();
        if (h >= 21 || h < 6) toggleCollapse(true);
      }

      heroArea?.addEventListener('click', () => toggleCollapse());

      // Setup Particles
      if (typeof particlesJS !== 'undefined') {
        particlesJS('particles-js', {
          particles: {
            number: { value: 40 },
            color: { value: ['#0ff','#f0f'] },
            shape: { type: 'circle' },
            opacity: { value: 0.4 },
            size: { value: 2.4 },
            move: { enable: true, speed: 1.5 }
          },
          retina_detect: true
        });
      }

      // Key Manager
      initKeyManager();

      // ORB Long Press (1.5s = Keys, 3s = Wheel)
      setupOrbLongPress();
    });

    // ========== ORB LONG PRESS ========== 
    function setupOrbLongPress() {
      const btn = document.getElementById('btn-arch');
      const DURATION_SHORT = 1500; // 1.5s para chaves
      const DURATION_LONG = 3000;  // 3s para wheel
      let timer1, timer2, t0;

      function start() {
        t0 = Date.now();

        // Timer para 1.5s (Key Manager)
        timer1 = setTimeout(() => {
          openKeyManager();
        }, DURATION_SHORT);

        // Timer para 3s (Arch Wheel)
        timer2 = setTimeout(() => {
          openArchOverlay();
        }, DURATION_LONG);
      }

      function cancel() {
        clearTimeout(timer1);
        clearTimeout(timer2);
        t0 = null;
      }

      btn.addEventListener('pointerdown', start, { passive: true });
      btn.addEventListener('pointerup', cancel);
      btn.addEventListener('pointerleave', cancel);
    }

    // ========== KEY MANAGER ========== 
    function initKeyManager() {
      if (window.__keyManagerInitialised) return;
      window.__keyManagerInitialised = true;

      const LS_KEYS = {
        OR_KEYS: 'OR_KEYS',
        OR_ACTIVE: 'OR_ACTIVE',
        TRAIN_BASE: 'TRAIN_BASE_TEXT',
        TRAIN_BASE_NAME: 'TRAIN_BASE_NAME',
        TRAIN_BASE_ENABLED: 'TRAIN_BASE_ENABLED',
        TRAIN_EXTRAS: 'TRAIN_EXTRAS'
      };

      const qs = (s, r=document) => r.querySelector(s);
      const store = {
        get(k, d) { try { return JSON.parse(localStorage.getItem(k)) ?? d; } catch(e) { return d; } },
        set(k, v) { localStorage.setItem(k, JSON.stringify(v)); }
      };

      const panel = qs('#keymgrPanel');
      const closeBtn = qs('#keymgrClose');
      const orKeyName = qs('#orKeyName');
      const orKeyValue = qs('#orKeyValue');
      const btnPaste = qs('#btnPasteKey');
      const btnSaveKey = qs('#btnSaveKey');
      const keysList = qs('#keysList');
      const baseName = qs('#baseTrainName');
      const baseText = qs('#baseTrainText');
      const baseFile = qs('#baseTrainFile');
      const btnLoadBase = qs('#btnLoadBaseTxt');
      const btnApply = qs('#btnApplyBaseTxt');
      const baseEnabled = qs('#baseTrainEnabled');
      const extraName = qs('#extraName');
      const extraFile = qs('#extraFile');
      const btnLoadExt = qs('#btnLoadExtraTxt');
      const extrasList = qs('#extrasList');
      const keymgrUserName = qs('#keymgrUserName');
      const keymgrAssistantName = qs('#keymgrAssistantName');

      closeBtn?.addEventListener('click', () => panel.classList.remove('open'));

      btnPaste?.addEventListener('click', async () => {
        try { orKeyValue.value = await navigator.clipboard.readText(); }
        catch(e) { alert('Não consegui ler o clipboard.'); }
      });

      function renderKeys(){
        const list = store.get(LS_KEYS.OR_KEYS, []);
        const active = store.get(LS_KEYS.OR_ACTIVE, null);
        keysList.innerHTML = '';
        list.forEach((k, idx) => {
          const item = document.createElement('div');
          item.className = 'item';
          item.innerHTML = '<div class="badges"><span class="badge">' + (k.name || ('Chave ' + (idx+1))) + '</span>' + (active === k.name ? '<span class="badge">ATIVA</span>' : '') + '</div>';
          const actions = document.createElement('div');
          actions.className = 'row';
          const btnAct = document.createElement('button');
          btnAct.className = 'btnx';
          btnAct.textContent = 'Ativar';
          btnAct.addEventListener('click', () => { store.set(LS_KEYS.OR_ACTIVE, k.name); renderKeys(); });
          const btnDel = document.createElement('button');
          btnDel.className = 'btnx';
          btnDel.textContent = 'Excluir';
          btnDel.addEventListener('click', () => { list.splice(idx,1); store.set(LS_KEYS.OR_KEYS, list); if (active === k.name) store.set(LS_KEYS.OR_ACTIVE, null); renderKeys(); });
          actions.append(btnAct, btnDel);
          item.append(actions);
          keysList.append(item);
        });
      }

      btnSaveKey?.addEventListener('click', () => {
        const name = (orKeyName.value || '').trim();
        const val = (orKeyValue.value || '').trim();
        if (!val || !/^sk-/.test(val)) { return alert('Cole uma chave começando com sk-'); }
        const list = store.get(LS_KEYS.OR_KEYS, []);
        const i = list.findIndex(x => x.name === name);
        if (i >= 0) list[i].key = val; else list.push({ name: name || ('Chave ' + (list.length+1)), key: val });
        store.set(LS_KEYS.OR_KEYS, list);
        if (!store.get(LS_KEYS.OR_ACTIVE, null)) store.set(LS_KEYS.OR_ACTIVE, list[0].name);
        orKeyValue.value = '';
        renderKeys();
        alert('Chave salva.');
      });

      window.getOpenRouterKey = function() {
        const list = store.get(LS_KEYS.OR_KEYS, []);
        const active = store.get(LS_KEYS.OR_ACTIVE, null);
        const item = list.find(x => x.name === active) || list[0];
        return item ? item.key : null;
      };

      // Training base
      function loadBaseFromLS() {
        baseName.value = store.get(LS_KEYS.TRAIN_BASE_NAME, 'Base (inline)');
        baseText.value = store.get(LS_KEYS.TRAIN_BASE, '') || (window.TRAININGS && window.TRAININGS.unificado) || '';
        baseEnabled.checked = store.get(LS_KEYS.TRAIN_BASE_ENABLED, true);
      }
      loadBaseFromLS();

      btnLoadBase?.addEventListener('click', () => baseFile.click());
      baseFile?.addEventListener('change', async (e) => {
        const f = e.target.files[0];
        if (!f) return;
        const txt = await f.text();
        baseName.value = f.name.replace(/\.txt$/i, '');
        baseText.value = txt;
      });

      btnApply?.addEventListener('click', () => {
        store.set(LS_KEYS.TRAIN_BASE_NAME, baseName.value.trim() || 'Base');
        store.set(LS_KEYS.TRAIN_BASE, baseText.value || '');
        store.set(LS_KEYS.TRAIN_BASE_ENABLED, baseEnabled.checked);
        alert('Treinamento Base atualizado.');
      });

      // Extras
      function renderExtras() {
        const list = store.get(LS_KEYS.TRAIN_EXTRAS, []);
        extrasList.innerHTML = '';
        list.forEach((ext, idx) => {
          const item = document.createElement('div');
          item.className = 'item';
          item.innerHTML = '<div class="badges"><span class="badge">' + (ext.name || ('Extra ' + (idx+1))) + '</span>' + (ext.enabled ? '' : '<span class="badge">DESATIVADO</span>') + '</div>';
          const actions = document.createElement('div');
          actions.className = 'row';
          const btnAct = document.createElement('button');
          btnAct.className = 'btnx';
          btnAct.textContent = ext.enabled ? 'Desativar' : 'Ativar';
          btnAct.addEventListener('click', () => { ext.enabled = !ext.enabled; store.set(LS_KEYS.TRAIN_EXTRAS, list); renderExtras(); });
          const btnDel = document.createElement('button');
          btnDel.className = 'btnx';
          btnDel.textContent = 'Excluir';
          btnDel.addEventListener('click', () => { list.splice(idx,1); store.set(LS_KEYS.TRAIN_EXTRAS, list); renderExtras(); });
          actions.append(btnAct, btnDel);
          item.append(actions);
          extrasList.append(item);
        });
      }

      function addExtra(name, text) {
        const list = store.get(LS_KEYS.TRAIN_EXTRAS, []);
        list.push({ name: name || ('Extra ' + (list.length+1)), text, enabled: true });
        store.set(LS_KEYS.TRAIN_EXTRAS, list);
        renderExtras();
      }

      btnLoadExt?.addEventListener('click', () => extraFile.click());
      extraFile?.addEventListener('change', async (e) => {
        const f = e.target.files[0];
        if (!f) return;
        const txt = await f.text();
        const name = (extraName.value || f.name.replace(/\.txt$/i, '')).trim();
        if (!name) { return alert('Nome do extra é obrigatório'); }
        addExtra(name, txt);
        extraName.value = '';
        extraFile.value = '';
      });

      renderKeys();
      renderExtras();
    }

    function openKeyManager() {
      const panel = document.getElementById('keymgrPanel');
      if (panel) {
        panel.classList.add('open');
        if (document.getElementById('keymgrUserName')) document.getElementById('keymgrUserName').textContent = localStorage.getItem('userName') || '';
        if (document.getElementById('keymgrAssistantName')) document.getElementById('keymgrAssistantName').textContent = localStorage.getItem('assistantBase') || '';
      }
    }

    // ========== ARCHETYPES ========== 
    const ARCHETYPES = [
      { name:'kobllux', p:'#C9A84C', s:'#8B4513', a:'#F0C060', f:432, e:'∞', r:'VERDADE · INTEGRAR' },
      { name:'atlas', p:'#8e9aaf', s:'#5c6478', a:'#b0bec5', f:432, e:'🗿', r:'FUNDAÇÃO · ESTRUTURA' },
      { name:'nova', p:'#00e5ff', s:'#0099cc', a:'#80f4ff', f:528, e:'⚡', r:'ENERGIA · VELOCIDADE' },
      { name:'vitalis', p:'#00e070', s:'#00a050', a:'#80ffb8', f:639, e:'🌿', r:'VIDA · CRESCIMENTO' },
      { name:'pulse', p:'#ff7020', s:'#cc3800', a:'#ffaa60', f:741, e:'🔥', r:'IMPULSO · AÇÃO' },
      { name:'kaos', p:'#ff2a6d', s:'#aa0040', a:'#ff80a0', f:852, e:'🌪', r:'CAOS · TRANSFORMAÇÃO' }
    ];

    function buildArchWheel() {
      const wheel = document.getElementById('archWheel');
      wheel.innerHTML = '';
      ARCHETYPES.forEach((arch) => {
        const chip = document.createElement('div');
        chip.className = 'arch-chip';
        chip.style.setProperty('--a-color', arch.a);
        chip.style.setProperty('--a-prim', arch.p);
        chip.style.setProperty('--a-sec', arch.s);
        chip.innerHTML = `<div class="a-orb" style="background:radial-gradient(circle at 35% 30%, ${arch.a} 0%, transparent 50%), radial-gradient(circle at 70% 70%, ${arch.p} 0%, ${arch.s} 100%);"></div><div class="a-name">${arch.name}</div><div class="a-freq">${arch.f}Hz</div>`;
        chip.addEventListener('click', () => {
          applyArchetype(arch);
          closeArchOverlay();
        });
        wheel.appendChild(chip);
      });
    }

    function applyArchetype(arch) {
      const root = document.documentElement;
      root.style.setProperty('--kob-voice-primary', arch.p);
      root.style.setProperty('--kob-voice-secondary', arch.s);
      root.style.setProperty('--kob-voice-accent', arch.a);
      root.style.setProperty('--arch-color', arch.p);
      const hud = document.getElementById('hudStatus');
      if (hud) hud.textContent = arch.name.toUpperCase() + ' · ' + arch.f + 'Hz';
    }

    function openArchOverlay() {
      const overlay = document.getElementById('arch-overlay');
      if (overlay) overlay.classList.add('open');
    }

