      const overlay = document.getElementById('arch-overlay');
      if (overlay) overlay.classList.remove('open');
    }

    document.getElementById('arch-overlay')?.addEventListener('click', (e) => {
      if (e.target === document.getElementById('arch-overlay')) closeArchOverlay();
    });

    // Initialize arch wheel on load
    window.addEventListener('load', buildArchWheel);
  </script>
