      </div>

      <div class="form-group">
        <label for="bankEntryName">Chave/ID</label>
        <input id="bankEntryName" type="text" placeholder="Ex: API_PROD, DB_MASTER">
      </div>

      <div class="form-group">
        <label for="bankEntryValue">Valor (será criptografado)</label>
        <textarea id="bankEntryValue" placeholder="Cole seu token/chave aqui" style="min-height:80px;"></textarea>
      </div>

      <div class="form-group">
        <label for="bankEntryDesc">Descrição</label>
        <input id="bankEntryDesc" type="text" placeholder="O que é este valor?">
      </div>

      <div class="btn-row">
        <button class="btn" id="btnBankSave">💾 Salvar Criptografado</button>
        <button class="btn" id="btnBankView">👁 Ver Banco</button>
      </div>

      <div id="bankContent" class="bank-content" style="margin-top:20px;"></div>
    </div>
  </div>

  <!-- ========== ARCH OVERLAY ========== -->
  <div id="arch-overlay" style="position:fixed; inset:0; z-index:var(--z-overlay); display:none; align-items:center; justify-content:center; background:rgba(2,2,10,0.75); backdrop-filter:blur(8px);">
    <div id="archWheel" style="display:flex; flex-wrap:wrap; gap:8px; justify-content:center; max-width:380px; background:linear-gradient(135deg, rgba(10,10,30,0.97), rgba(5,5,18,0.99)); border:1px solid var(--border); border-radius:22px; padding:18px; box-shadow:0 0 60px var(--arch-glow);"></div>
  </div>

  <script>
    // ========== ORB CONFIGURATION ==========
    const orbConfig = {
      name: 'KOBLLUX',
      primary: '#C9A84C',
      secondary: '#8B4513',
      accent: '#F0C060',
      freq: 432
    };

    function updateOrbGradient() {
      const gradient = `radial-gradient(circle at 28% 28%, ${orbConfig.accent} 0%, rgba(255,255,255,0.08) 12%, transparent 55%), radial-gradient(circle at 72% 72%, ${orbConfig.primary} 0%, ${orbConfig.secondary} 100%)`;

      document.querySelectorAll('.orb-core').forEach(el => {
        el.style.background = gradient;
        el.style.boxShadow = `0 0 18px ${orbConfig.primary}`;
      });

      document.documentElement.style.setProperty('--kob-voice-primary', orbConfig.primary);
      document.documentElement.style.setProperty('--kob-voice-secondary', orbConfig.secondary);
      document.documentElement.style.setProperty('--kob-voice-accent', orbConfig.accent);
      document.documentElement.style.setProperty('--arch-glow', `rgba(201,168,76,0.35)`);

      document.getElementById('hudStatus').textContent = orbConfig.name.toUpperCase() + ' · ' + orbConfig.freq + 'Hz';

      localStorage.setItem('orbConfig', JSON.stringify(orbConfig));
    }

    function loadOrbConfig() {
      const saved = localStorage.getItem('orbConfig');
      if (saved) {
        Object.assign(orbConfig, JSON.parse(saved));
        document.getElementById('orbName').value = orbConfig.name;
        document.getElementById('orbColor').value = orbConfig.primary;
        document.getElementById('orbColorSecondary').value = orbConfig.secondary;
        document.getElementById('orbColorAccent').value = orbConfig.accent;
        document.getElementById('orbFreq').value = orbConfig.freq;
        updateOrbGradient();
      }
    }

    document.getElementById('orbSave')?.addEventListener('click', () => {
      orbConfig.name = document.getElementById('orbName').value || 'ORB';
      orbConfig.primary = document.getElementById('orbColor').value || '#C9A84C';
      orbConfig.secondary = document.getElementById('orbColorSecondary').value || '#8B4513';
      orbConfig.accent = document.getElementById('orbColorAccent').value || '#F0C060';
      orbConfig.freq = parseInt(document.getElementById('orbFreq').value) || 432;

      updateOrbGradient();
      document.getElementById('orbCardOverlay').classList.remove('open');
      alert('✓ ORB Sincronizado!');
    });

    document.getElementById('orbReset')?.addEventListener('click', () => {
      orbConfig.name = 'KOBLLUX';
      orbConfig.primary = '#C9A84C';
      orbConfig.secondary = '#8B4513';
      orbConfig.accent = '#F0C060';
      orbConfig.freq = 432;
      loadOrbConfig();
      updateOrbGradient();
    });

    document.getElementById('orbCardClose')?.addEventListener('click', () => {
      document.getElementById('orbCardOverlay').classList.remove('open');
    });

    document.getElementById('orbCardOverlay')?.addEventListener('click', (e) => {
      if (e.target === document.getElementById('orbCardOverlay')) {
        document.getElementById('orbCardOverlay').classList.remove('open');
      }
    });

    // ========== KEY MANAGER ==========
    const LS_KEYS = {
      OR_KEYS: 'OR_KEYS',
      OR_ACTIVE: 'OR_ACTIVE',
      TRAIN_BASE: 'TRAIN_BASE_TEXT',
      TRAIN_BASE_NAME: 'TRAIN_BASE_NAME',
      TRAIN_BASE_ENABLED: 'TRAIN_BASE_ENABLED',
      TRAIN_EXTRAS: 'TRAIN_EXTRAS',
      BANK_DATA: 'BANK_ENCRYPTED_DATA'
    };

    const store = {
      get(k, d) { try { return JSON.parse(localStorage.getItem(k)) ?? d; } catch(e) { return d; } },
      set(k, v) { localStorage.setItem(k, JSON.stringify(v)); }
    };

    function openKeyManager() {
      const panel = document.getElementById('keyManagerOverlay');
      if (panel) {
        panel.classList.add('open');
        document.getElementById('kmUserName').textContent = localStorage.getItem('userName') || 'Dual';
        document.getElementById('kmAssistantName').textContent = localStorage.getItem('assistantBase') || 'Infodose';
        renderKeys();
        renderExtras();
      }
    }

    function renderKeys() {
      const list = store.get(LS_KEYS.OR_KEYS, []);
      const active = store.get(LS_KEYS.OR_ACTIVE, null);
      const keysList = document.getElementById('keysList');
      keysList.innerHTML = '';

      list.forEach((k, idx) => {
        const item = document.createElement('div');
        item.className = 'key-item';
        const mask = k.key.substring(0, 8) + '...' + k.key.substring(k.key.length - 4);
        item.innerHTML = `<span class="badge">${k.name || 'Chave ' + (idx+1)}</span>${active === k.name ? '<span class="badge" style="background:rgba(0,200,0,0.2); color:#0f0;">✓ ATIVA</span>' : ''} <code>${mask}</code>`;
        const actions = document.createElement('div');
        actions.style.marginTop = '4px';
        actions.style.display = 'flex';
        actions.style.gap = '4px';

        const btnAct = document.createElement('button');
        btnAct.textContent = 'Ativar';
        btnAct.onclick = () => { store.set(LS_KEYS.OR_ACTIVE, k.name); renderKeys(); };

        const btnDel = document.createElement('button');
        btnDel.textContent = 'Excluir';
        btnDel.onclick = () => { list.splice(idx,1); store.set(LS_KEYS.OR_KEYS, list); renderKeys(); };

        actions.append(btnAct, btnDel);
        item.append(actions);
        keysList.append(item);
      });
    }

    document.getElementById('btnPasteKey')?.addEventListener('click', async () => {
      try { document.getElementById('orKeyValue').value = await navigator.clipboard.readText(); }
      catch(e) { alert('Não consegui ler o clipboard'); }
    });

    document.getElementById('btnSaveKey')?.addEventListener('click', () => {
      const name = document.getElementById('orKeyName').value.trim() || 'Chave';
      const val = document.getElementById('orKeyValue').value.trim();
      if (!val || !/^sk-/.test(val)) { alert('Cole uma chave começando com sk-'); return; }

      const list = store.get(LS_KEYS.OR_KEYS, []);
      const i = list.findIndex(x => x.name === name);
      if (i >= 0) list[i].key = val; else list.push({ name, key: val });
      store.set(LS_KEYS.OR_KEYS, list);
      if (!store.get(LS_KEYS.OR_ACTIVE)) store.set(LS_KEYS.OR_ACTIVE, list[0].name);

      document.getElementById('orKeyValue').value = '';
      renderKeys();
      alert('✓ Chave salva');
    });

    document.getElementById('btnLoadBaseTxt')?.addEventListener('click', () => {
      document.getElementById('baseTrainFile').click();
    });

    document.getElementById('baseTrainFile')?.addEventListener('change', async (e) => {
      const f = e.target.files[0];
      if (!f) return;
      const txt = await f.text();
      document.getElementById('baseTrainName').value = f.name.replace(/\.txt$/i, '');
      document.getElementById('baseTrainText').value = txt;
    });

    document.getElementById('btnApplyBaseTxt')?.addEventListener('click', () => {
      store.set(LS_KEYS.TRAIN_BASE_NAME, document.getElementById('baseTrainName').value || 'Base');
      store.set(LS_KEYS.TRAIN_BASE, document.getElementById('baseTrainText').value || '');
      store.set(LS_KEYS.TRAIN_BASE_ENABLED, document.getElementById('baseEnabled').checked);
      alert('✓ Treinamento Base atualizado');
    });

    function renderExtras() {
      const list = store.get(LS_KEYS.TRAIN_EXTRAS, []);
      const extrasList = document.getElementById('extrasList');
      extrasList.innerHTML = '';

      list.forEach((ext, idx) => {
        const item = document.createElement('div');
        item.className = 'extra-item';
        item.innerHTML = `<span class="badge">${ext.name}</span> ${ext.enabled ? '' : '<span class="badge" style="background:rgba(255,100,100,0.2); color:#ff6b6b;">INATIVO</span>'}`;
        const actions = document.createElement('div');
        actions.style.marginTop = '4px';
        actions.style.display = 'flex';
        actions.style.gap = '4px';

        const btnToggle = document.createElement('button');
        btnToggle.textContent = ext.enabled ? 'Desativar' : 'Ativar';
        btnToggle.onclick = () => { ext.enabled = !ext.enabled; store.set(LS_KEYS.TRAIN_EXTRAS, list); renderExtras(); };

        const btnDel = document.createElement('button');
        btnDel.textContent = 'Excluir';
        btnDel.onclick = () => { list.splice(idx,1); store.set(LS_KEYS.TRAIN_EXTRAS, list); renderExtras(); };

        actions.append(btnToggle, btnDel);
        item.append(actions);
        extrasList.append(item);
      });
    }

    document.getElementById('btnLoadExtraTxt')?.addEventListener('click', () => {
      document.getElementById('extraFile').click();
    });

    document.getElementById('extraFile')?.addEventListener('change', async (e) => {
      const f = e.target.files[0];
      if (!f) return;
      const txt = await f.text();
      const name = (document.getElementById('extraName').value || f.name.replace(/\.txt$/i, '')).trim();
      if (!name) { alert('Nome obrigatório'); return; }

      const list = store.get(LS_KEYS.TRAIN_EXTRAS, []);
      list.push({ name, text: txt, enabled: true });
      store.set(LS_KEYS.TRAIN_EXTRAS, list);
      document.getElementById('extraName').value = '';
      renderExtras();
    });

    document.getElementById('keyManagerClose')?.addEventListener('click', () => {
      document.getElementById('keyManagerOverlay').classList.remove('open');
    });

    document.getElementById('keyManagerOverlay')?.addEventListener('click', (e) => {
      if (e.target === document.getElementById('keyManagerOverlay')) {
        document.getElementById('keyManagerOverlay').classList.remove('open');
      }
    });

    // ========== BANK MANAGER WITH LONG PRESS ==========
    let bankPressTimer = null;

    document.getElementById('btnOpenBank')?.addEventListener('pointerdown', () => {
      bankPressTimer = setTimeout(() => {
        document.getElementById('keyManagerOverlay').classList.remove('open');
        document.getElementById('bankOverlay').classList.add('open');
      }, 2000);
    });

    document.getElementById('btnOpenBank')?.addEventListener('pointerup', () => {
      clearTimeout(bankPressTimer);
    });

    document.getElementById('btnOpenBank')?.addEventListener('pointerleave', () => {
      clearTimeout(bankPressTimer);
    });

    // Simple encryption (for demo - use proper crypto library in production)
    function simpleEncrypt(text, key) {
      return btoa(text + '::' + key).split('').reverse().join('');
    }

    function simpleDecrypt(encrypted, key) {
      try {
        const decrypted = atob(encrypted.split('').reverse().join(''));
        const [text, storedKey] = decrypted.split('::');
        return storedKey === key ? text : null;
      } catch (e) {
        return null;
      }
    }

    document.getElementById('btnBankSave')?.addEventListener('click', () => {
      const pass = document.getElementById('bankMasterPassword').value;
      const name = document.getElementById('bankEntryName').value;
      const value = document.getElementById('bankEntryValue').value;
      const desc = document.getElementById('bankEntryDesc').value;

      if (!pass || !name || !value) { alert('Preencha todos os campos'); return; }

      const encrypted = simpleEncrypt(value, pass);
      const bankData = store.get(LS_KEYS.BANK_DATA, []);
      bankData.push({
        id: Date.now(),
        name,
        desc,
        encrypted,
        createdAt: new Date().toISOString()
      });
      store.set(LS_KEYS.BANK_DATA, bankData);

      document.getElementById('bankEntryName').value = '';
      document.getElementById('bankEntryValue').value = '';
      document.getElementById('bankEntryDesc').value = '';
      alert('✓ Valor criptografado e salvo!');
      renderBankContent();
    });

    function renderBankContent() {
      const pass = document.getElementById('bankMasterPassword').value;
      const bankData = store.get(LS_KEYS.BANK_DATA, []);
      const content = document.getElementById('bankContent');
      content.innerHTML = '';

      bankData.forEach((entry) => {
        const decrypted = simpleDecrypt(entry.encrypted, pass);
        const div = document.createElement('div');
        div.className = 'bank-entry';
        div.innerHTML = `<strong>${entry.name}</strong> (${entry.desc})<br>
          ${decrypted ? `<code>${decrypted.substring(0, 20)}...</code>` : '<em style="color:#ff6b6b;">❌ Senha incorreta</em>'}<br>
          <small>${new Date(entry.createdAt).toLocaleString()}</small>`;
        content.append(div);
      });
    }

    document.getElementById('btnBankView')?.addEventListener('click', () => {
      renderBankContent();
    });

    document.getElementById('bankClose')?.addEventListener('click', () => {
      document.getElementById('bankOverlay').classList.remove('open');
    });

    document.getElementById('bankOverlay')?.addEventListener('click', (e) => {
      if (e.target === document.getElementById('bankOverlay')) {
        document.getElementById('bankOverlay').classList.remove('open');
      }
    });

    // ========== ORB BUTTON LONG PRESS ==========
    let orbPressTimer1 = null;
    let orbPressTimer2 = null;

    document.getElementById('btn-arch')?.addEventListener('pointerdown', () => {
      // 1.5s para Key Manager
      orbPressTimer1 = setTimeout(() => {
        openKeyManager();
      }, 1500);

      // 3s para Arch Overlay
      orbPressTimer2 = setTimeout(() => {
        document.getElementById('arch-overlay').classList.add('open');
      }, 3000);
    });

    document.getElementById('btn-arch')?.addEventListener('pointerup', () => {
      clearTimeout(orbPressTimer1);
      clearTimeout(orbPressTimer2);
    });

    document.getElementById('btn-arch')?.addEventListener('pointerleave', () => {
      clearTimeout(orbPressTimer1);
      clearTimeout(orbPressTimer2);
    });

    // Quick click abre ORB Config
    document.getElementById('btn-arch')?.addEventListener('click', (e) => {
      if (!orbPressTimer1 && !orbPressTimer2) {
        document.getElementById('orbCardOverlay').classList.add('open');
      }
    });

    // ========== ORB CARD OVERLAY ==========
    document.getElementById('orbCardOverlay')?.addEventListener('click', (e) => {
      if (e.target === document.getElementById('orbCardOverlay')) {
        document.getElementById('orbCardOverlay').classList.remove('open');
      }
    });

    // ========== ARCH OVERLAY ==========
    const ARCHETYPES = [
      { name:'atlas', p:'#8e9aaf', s:'#5c6478', a:'#b0bec5', e:'🗿' },
      { name:'nova', p:'#00e5ff', s:'#0099cc', a:'#80f4ff', e:'⚡' },
      { name:'vitalis', p:'#00e070', s:'#00a050', a:'#80ffb8', e:'🌿' },
      { name:'pulse', p:'#ff7020', s:'#cc3800', a:'#ffaa60', e:'🔥' },
      { name:'kaos', p:'#ff2a6d', s:'#aa0040', a:'#ff80a0', e:'🌪' },
      { name:'kobllux', p:'#C9A84C', s:'#8B4513', a:'#F0C060', e:'∞' },
    ];

    function buildArchWheel() {
      const wheel = document.getElementById('archWheel');
      wheel.innerHTML = '';
      ARCHETYPES.forEach((arch) => {
        const chip = document.createElement('button');
        chip.style.cssText = `
          display: flex;
          flex-direction: column;
          align-items: center;
          gap: 4px;
          padding: 8px 10px;
          border-radius: 12px;
          border: 1px solid rgba(201,168,76,0.3);
          background: rgba(255,255,255,0.04);
          cursor: pointer;
          color: ${arch.p};
          font-family: var(--mono);
          min-width: 56px;
          transition: all 0.2s;
        `;
        chip.innerHTML = `<div style="font-size:20px;">${arch.e}</div><div style="font-size:7px; letter-spacing:1px;">${arch.name.toUpperCase()}</div>`;
        chip.onmouseover = () => chip.style.transform = 'scale(1.1)';
        chip.onmouseout = () => chip.style.transform = 'scale(1)';
        chip.onclick = () => {
          orbConfig.name = arch.name.toUpperCase();
          orbConfig.primary = arch.p;
          orbConfig.secondary = arch.s;
          orbConfig.accent = arch.a;
          updateOrbGradient();
          document.getElementById('arch-overlay').classList.remove('open');
        };
        wheel.append(chip);
      });
    }

    document.getElementById('arch-overlay')?.addEventListener('click', (e) => {
      if (e.target === document.getElementById('arch-overlay')) {
        document.getElementById('arch-overlay').classList.remove('open');
      }
    });

    // ========== INIT ==========
    document.addEventListener('DOMContentLoaded', () => {
      loadOrbConfig();
      buildArchWheel();
      updateOrbGradient();
    });
  </script>
</body>
</html>
